input.command:
_GSD_SHIM_NAME="gsd-tools.cjs"; _GSD_RUNTIME_ROOT="${RUNTIME_DIR:-$(git rev-parse --show-toplevel 2>/dev/null || pwd)}"; GSD_TOOLS="${_GSD_RUNTIME_ROOT}/gsd-core/bin/${_GSD_SHIM_NAME}"
if [ -f "$GSD_TOOLS" ]; then :;
elif [ -f "${_GSD_RUNTIME_ROOT}/.claude/gsd-core/bin/${_GSD_SHIM_NAME}" ]; then GSD_TOOLS="${_GSD_RUNTIME_ROOT}/.claude/gsd-core/bin/${_GSD_SHIM_NAME}";
elif command -v gsd-tools >/dev/null 2>&1; then GSD_TOOLS="$(command -v gsd-tools)";
elif [ -f "$HOME/.claude/gsd-core/bin/${_GSD_SHIM_NAME}" ]; then GSD_TOOLS="$HOME/.claude/gsd-core/bin/${_GSD_SHIM_NAME}";
else echo "ERROR: gsd-tools.cjs not found"; exit 1; fi
echo "GSD_TOOLS=$GSD_TOOLS"
echo "--- git branch ---"
git branch --show-current

GSD_TOOLS="/home/janfr/.claude/gsd-core/bin/gsd-tools.cjs"
gsd_run() { node "$GSD_TOOLS" "$@"; }
SCRATCH="/tmp/claude-1000/-home-janfr-dev-pc-switcher/48e68ed7-012f-4c12-b00f-cda334ec193c/scratchpad"
echo "=== plan:pre hooks (activeHooks summary) ==="
gsd_run loop render-hooks plan:pre --raw > "$SCRATCH/plan-pre-hooks.json" 2>/dev/null && echo "captured ($(wc -c < "$SCRATCH/plan-pre-hooks.json") bytes)" || echo "(render-hooks failed)"
node -e '
try {
  const fs=require("fs");
  const j=JSON.parse(fs.readFileSync(process.argv[1],"utf8"));
  const hooks=j.activeHooks||j.hooks||[];
  if(!Array.isArray(hooks)||hooks.length===0){console.log("activeHooks: EMPTY (all plan:pre hooks inactive)");}
  else{for(const h of hooks){console.log(`- capId=${h.capId} kind=${h.kind} skill=${h.ref&&h.ref.skill||""} agent=${h.ref&&h.ref.agent||""} check=${h.check&&h.check.query||""} blocking=${h.blocking}`);}}
}catch(e){console.log("parse error: "+e.message);}
' "$SCRATCH/plan-pre-hooks.json"
echo ""
echo "=== UI plan-gate check ==="
gsd_run check ui-plan-gate "01" --raw 2>/dev/null || echo "(ui-plan-gate check unavailable)"

GSD_TOOLS="/home/janfr/.claude/gsd-core/bin/gsd-tools.cjs"
gsd_run() { node "$GSD_TOOLS" "$@"; }
SCRATCH="/tmp/claude-1000/-home-janfr-dev-pc-switcher/48e68ed7-012f-4c12-b00f-cda334ec193c/scratchpad"
echo "=== §5.65 drift codebase-drift (non-blocking) ==="
gsd_run verify codebase-drift 2>/dev/null > "$SCRATCH/drift.json" || echo '{"skipped":true}' > "$SCRATCH/drift.json"
node -e '
const fs=require("fs");
let j={};try{j=JSON.parse(fs.readFileSync(process.argv[1],"utf8"));}catch(e){console.log("(unparseable)");process.exit(0);}
console.log("skipped:",j.skipped, "action_required:",j.action_required);
if(j.action_required && j.message) console.log("MESSAGE:\n"+j.message);
' "$SCRATCH/drift.json"
echo ""
echo "=== planner-targeted contributions (into==planner) + security configValues ==="
node -e '
const fs=require("fs");
const j=JSON.parse(fs.readFileSync(process.argv[1],"utf8"));
const hooks=j.activeHooks||j.hooks||[];
for(const h of hooks){
  if(h.kind==="contribution"){
    console.log("--- contribution capId="+h.capId+" into="+(h.into||"(unset)")+" ---");
    if(h.configValues) console.log("configValues: "+JSON.stringify(h.configValues));
    const frag=h.fragment&&(h.fragment.inline||h.fragment.text);
    console.log("fragment length: "+(frag?frag.length:0));
  }
}
' "$SCRATCH/plan-pre-hooks.json"

SCRATCH="/tmp/claude-1000/-home-janfr-dev-pc-switcher/48e68ed7-012f-4c12-b00f-cda334ec193c/scratchpad"
node -e '
const fs=require("fs");
const j=JSON.parse(fs.readFileSync(process.argv[1],"utf8"));
const hooks=j.activeHooks||j.hooks||[];
let out="";
for(const h of hooks){
  if(h.kind==="contribution" && (h.into==="planner")){
    const frag=h.fragment&&(h.fragment.inline||h.fragment.text)||"";
    out+="\n===== capId="+h.capId+" (into=planner) =====\n"+frag+"\n";
  }
}
fs.writeFileSync(process.argv[2], out);
process.stdout.write(out);
' "$SCRATCH/plan-pre-hooks.json" "$SCRATCH/planner-contributions.txt"

GSD_TOOLS="/home/janfr/.claude/gsd-core/bin/gsd-tools.cjs"
gsd_run() { node "$GSD_TOOLS" "$@"; }
cd /home/janfr/dev/pc-switcher
PHASE_DIR=".planning/phases/01-home-sync-mvp-user-data-sync"
PHASE_REQ_IDS="REQ-sync-scope-user-data, REQ-machine-specific-exclusions, REQ-sync-scope-file-metadata, REQ-manual-sync-workflow, REQ-terminal-ux"

echo "=== §13e gap-analysis (advisory, non-blocking) ==="
gsd_run check gap-analysis.plan-post "$PHASE_DIR" "$PHASE_REQ_IDS" --raw 2>&1 | node -e '
const fs=require("fs");let s=fs.readFileSync(0,"utf8");
try{const j=JSON.parse(s);console.log("block:",j.block);
if(j.summary)console.log("summary:",j.summary);
if(j.table)console.log("table:\n"+j.table);
if(!j.block&&!j.table&&!j.summary)console.log("no gaps reported");
}catch(e){console.log("raw:",s.slice(0,400));}'

echo ""
echo "=== §13d git status (what needs committing) ==="
git status --short
